        public static bool ConfundFile(string path, string key)
        {
            if (IsFileConfunded(path))
            {
                SpitOut("{0} is already confunded", path);
                return false;
            }
            var success = ConfundFile(path, key, unconfund: false);
            SpitOut("{0} has {1} confunded", path,
            success
                ? "been successfully"
                : "FAILED to be");
            return success;
        }

        public static void ConfundAll(string path, string key, string pattern)
        {
            foreach (var f in Directory.GetFiles(path, pattern))
            {
                ConfundFile(f, key);
            }
            SpitOut("{0} has been processed", path);
            return;
        }

        public static bool UnConfundFile(string path, string key)
        {
            if (!IsFileConfunded(path))
            {
                SpitOut("{0} is not confunded", path);
                return false;
            }
            var success = ConfundFile(path, key, unconfund: true);
            SpitOut("{0} has {1} unconfunded", path,
            success
                ? "been successfully"
                : "FAILED to be");
            return success;
        }

        public static void UnConfundAll(string path, string key, string pattern)
        {
            foreach (var f in Directory.GetFiles(path, pattern))
            {
                UnConfundFile(f, key);
            }
            SpitOut("{0} has been processed", path);
        }

        public static bool ChangeKeyFile(string path, string key, string newKey)
        {
             if (!IsFileConfunded(path))
            {
                SpitOut("{0} is not confunded", path);
                return false;
            }
            var unconfunded = ConfundFile(path, key, unconfund: true);
            var reconfunded = ConfundFile(path, newKey, unconfund: false);
            var success = unconfunded && reconfunded;
            SpitOut("{0} has {1} unconfunded and reconfounded with the new key", path,
            success
                ? "been successfully"
                : "FAILED to be");
            return success;
        }

        public static void ChangeKeyAll(string path, string key, string newKey, string pattern)
        {
             foreach (var f in Directory.GetFiles(path, pattern))
            {
                ChangeKeyFile(f, key, newKey);
            }
            SpitOut("{0} has been processed", path);
        }

        public static bool ConfundFile(string path, string key, bool unconfund)
        {
            bool success = false;
            try
            {
                if (unconfund)
                {
                    if (!RemoveConfundMarkFromFile(path))
                    {
                        Console.Error.WriteLine("Failed to remove \"confund mark\" from file {0}", path);
                        return false;
                    }
                }

                FileInfo fi = new(path);
                int bufferLength = (int)Math.Min(4096, fi.Length);
                using var file = fi.Open(FileMode.Open, FileAccess.ReadWrite);
                byte[] buf = new byte[bufferLength];
                file.ReadExactly(buf, 0, bufferLength);
                buf = EncryptData(buf, key, ungarble: unconfund);
                file.Position = 0;
                file.Write(buf, 0, bufferLength);
                file.Close();

                if (unconfund || AppendConfundMarkToFile(path))
                {
                    success = true;
                }
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine(ex.Message);
            }

            return success;
        }

        public static bool AppendConfundMarkToFile(string path)
        {
            try
            {
                using FileStream fs = new(path, FileMode.Append, FileAccess.Write);
                try
                {
                    fs.Write(_confundedMark, 0, _confundedMark.Length);
                }
                catch (Exception ex)
                {
                    Console.Error.WriteLine("Failed to append the \"confund mark\" to file {0}. Error: {1}", path, ex.Message);
                    return false;
                }
                finally
                {
                    fs.Close();
                }

                return true;
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine(ex.Message);
                return false;
            }
        }

        public static bool RemoveConfundMarkFromFile(string path)
        {
            try
            {
                int bytesToRemove = _confundedMark.Length;
                using FileStream fs = new(path, FileMode.Open, FileAccess.ReadWrite);
                try
                {
                    long fileLength = fs.Length;
                    if (bytesToRemove > fileLength)
                    {
                        return false;
                    }
                    // Truncate the file by removing the mark from the end
                    fs.SetLength(fileLength - bytesToRemove);
                    return true;
                }
                catch (Exception ex)
                {
                    Console.Error.WriteLine("Failed to remove the \"confund mark\" from file {0}. Error: {1}", path, ex.Message);
                    return false;
                }
                finally
                {
                    fs.Close();
                }
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine(ex.Message);
                return false;
            }
        }

        public static bool IsFileConfunded(string path)
        {
            bool isConfunded = false;
            FileInfo fi = new(path);

            if (fi.Length < _confundedMark.Length)
            {
                return false;
            }
            int bufLen = _confundedMark.Length;
            try
            {
                using var file = fi.Open(FileMode.Open, FileAccess.Read);
                file.Seek(-bufLen, SeekOrigin.End);
                byte[] buf = new byte[bufLen];
                file.ReadExactly(buf, 0, bufLen);

                isConfunded = buf.SequenceEqual(_confundedMark);
            }
            catch (Exception ex)
            {
                Console.Error.WriteLine(ex.Message);
            }

            return isConfunded;
        }

        public static byte[] EncryptData(byte[] data, string encryptionKey, bool ungarble = false)
        {
            using var aes = Aes.Create();
            aes.Key = Convert.FromBase64String(encryptionKey);
            aes.Mode = CipherMode.ECB;
            aes.Padding = PaddingMode.None;

            int numBlocks = (data.Length + 15) / 16;
            byte[] counter = new byte[numBlocks * 16];
            for (int i = 0; i < numBlocks; i++)
            {
                byte[] bytes = BitConverter.GetBytes(i);
                Buffer.BlockCopy(bytes, 0, counter, i * 16, bytes.Length);
            }

            using var encryptor = aes.CreateEncryptor();
            byte[] keystream = encryptor.TransformFinalBlock(counter, 0, counter.Length);

            byte[] result = new byte[data.Length];
            for (int i = 0; i < data.Length; i++)
            {
                result[i] = (byte)(data[i] ^ keystream[i]);
            }
            return result;
        }
    }
